];

function getPieceColor(pieceType, pieceColor) {
    if (pieceColor === 'Black') {
        return '#2c3e50'; // Darker, more noticeable black
    } else if (pieceColor === 'White') {
        return '#ffffff'; // White fill for pieces
    } else {
        return '#cccccc'; // Default placeholder color
    }
}

function drawPiece(context, row, col, piece) {
    if (!piece) return;

    let x = col * SQUARE_SIZE + SQUARE_SIZE / 2;
    let y = row * SQUARE_SIZE + SQUARE_SIZE / 2;

    // Determine piece color based on row convention, not just piece type in this simplified setup
