    let pieceFillColor = getPieceColor(piece, pieceColor);

    // Draw placeholder circle (updated dimensions for better fit)
    context.fillStyle = pieceFillColor;
    context.beginPath();
    context.arc(x, y, SQUARE_SIZE / 3.5, 0, Math.PI * 2);
    context.fill();

    // Draw text (Piece Type)
    context.fillStyle = pieceColor === 'Black' ? 'white' : 'black'; 
    context.font = `${SQUARE_SIZE * 0.6}px Arial`;
    context.textAlign = 'center';
    context.textBaseline = 'middle';
    context.fillText(String(piece), x, y);
}

function drawBoard() {
    context.clearRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < 8; i++) { // i is row
